<template>
  <img
      :src="src"
      class="inuni-logo"
      :class="variant"
      alt="InUni"
      :style="{ height: heightPx, width: 'auto' }"
  />
</template>

<script>
export default {
  name: 'InUniLogo',
  props: {
    height: { type: [Number, String], default: 44 },
    variant: { type: String, default: '' },
  },
  computed: {
    heightPx() {
      return typeof this.height === 'number' ? this.height + 'px' : this.height
    },
    src() {
      return 'data:image/png;base64,'
    },
  },
}
</script>

<style scoped>
.inuni-logo { display: block; object-fit: contain; }
.inuni-logo--compact { height: 36px; }
</style>